# -*- coding: UTF-8 -*-                                  # 指定源码文件使用 UTF-8 编码，防止中文乱码#!/usr/bin/env python2                                   # 显式指定用 python2 解释器执行，防止系统默认 python3import cv2                                               # 引入 OpenCV 图像处理库import os                                                # 引入操作系统接口（本例未主动使用，但常配套备用）import numpy as np                                       # 引入数值计算库，用于数组、矩阵运算import time                                              # 引入时间相关函数，如 sleep、计时import rospy                                             # 引入 ROS Python 客户端（虽然脚本里没再出现 rospy.*，但保留兼容）from pymycobot.mycobot import MyCobot                    # 从 pymycobot 包导入 MyCobot 机械臂控制类from opencv_yolo import yolo                             # 导入自己封装的 YOLO 检测工具类import math                                              # 数学函数库（本例未主动使用，保留备用）from GrabParams import grabParams                        # 导入自己写的参数配置文件（含坐标、速度、偏置等）import basic                                             # 自己封装的机械臂基础动作库（移动、夹爪等）import argparse                                          # 命令行参数解析库，用于启动时接收 --debug 参数# -------------------- 全局变量 --------------------add=5add1 = 5                                                 # 用来记录“第一次识别到的类别索引”，后续分类放置时做比对add2 = 5                                                 # 预留变量，本例未实际使用parser = argparse.ArgumentParser(description='manual to this script')  # 新建参数解析器对象parser.add_argument("--debug", type=bool, default="True")              # 允许命令行传入 --debug True/False 控制调试显示args = parser.parse_args()                               # 真正解析命令行参数，结果保存在 args 对象中height_bias = grabParams.height_bias                     # 从配置文件读取“抓取高度偏移量”coords = grabParams.coords_ready                         # 从配置文件读取“机械臂待命坐标”done = grabParams.done                                   # 从配置文件读取“完成标志位”初始值CLASSES = ("cat ", "bird ")                              # YOLO 模型可识别的两个类别名字（注意带空格，与训练标签一致）LGJ_speed=90# ==================== 核心类 ====================class Detect_marker(object):                             # 封装“检测-抓取-放置”整个流程的类    def __init__(self):                                  # 构造函数，类实例化时自动运行        super(Detect_marker, self).__init__()            # 经典类（python2）初始化写法，避免多继承隐患        self.mc = MyCobot(grabParams.usb_dev, grabParams.baudrate)  # 新建机械臂对象，指定串口设备名与波特率        self.mc.power_on()                               # 给机械臂上电（电机使能）        self.yolo = yolo()                               # 新建 YOLO 检测器实例        # 以下变量用于后续计算裁剪/映射，先全部初始化为 0        self.x1 = self.x2 = self.y1 = self.y2 = 0        # 图像裁剪左上角、右下角坐标（本例未实际使用）        self.sum_x1 = self.sum_x2 = self.sum_y2 = self.sum_y1 = 0  # 累加求平均用（本例未实际使用）        self.c_x, self.c_y = grabParams.IMG_SIZE / 2, grabParams.IMG_SIZE / 2  # 图像中心像素坐标，后续求偏移量        self.ratio = grabParams.ratio                    # 像素 → 实际距离的换算比例（单位：mm/px）    # ---------------- 抓取动作 ----------------    def move(self, x, y):                                # 输入：目标在图像中的像素偏移 x/y        global height_bias, done                         # 使用全局变量，允许在函数内修改        # 计算机械臂目标坐标：待命坐标 + 偏移 - 微调，高度用配置偏置        coords_target = [coords[0] + int(x) - 4, coords[1] + int(y), height_bias, coords[3], coords[4], coords[5]]        basic.move_to_target_coords(coords_target, grabParams.GRAB_MOVE_SPEED)  # 调用基础库移动到目标        basic.grap(True)                                 # 关闭夹爪，完成抓取        LGJ_angles=self.mc.get_angles()        LGJ_angles[1]= LGJ_angles[1]+35        if LGJ_angles[1]>=180:            LGJ_angles[1]=180        self.mc.send_angles(LGJ_angles, LGJ_speed)          #angles = [10.1, -22.76, -20.3, -28.74, -5.27, 57.56]  # 抓取后“抬起来”的安全角度        #self.mc.send_angles(angles, 60)                  # 以 30 % 速度运动到安全角度        time.sleep(0.8)                                  # 等待动作完成        done = True                                      # 设置全局完成标志        print("Done")                                    # 终端打印提示        self.mc.set_color(0, 255, 0)                     # 机械臂 LED 变绿色，表示“当前空闲”    # ---------------- 初始化机械臂 ----------------    def init_mycobot(self):                              # 让机械臂回到待命姿态        basic.grap(False)                                # 先张开夹爪        #time.sleep(0.5)                                    # 等待 1 s        basic.move_to_target_coords(coords, grabParams.GRAB_MOVE_SPEED)  # 移动到配置文件中的待命坐标    # ---------------- 像素 → 实际距离 ----------------    def get_position(self, x, y):                        # 输入：目标像素坐标；输出：相对机械臂的 mm 偏移        wx = wy = 0                                      # 初始化实际偏移量        if grabParams.grab_direct == "front":            # 如果摄像头朝“前方”安装            wx = (self.c_y - y) * self.ratio             # 计算 X 方向（机械臂坐标系）偏移            wy = (self.c_x - x) * self.ratio             # 计算 Y 方向偏移        elif grabParams.grab_direct == "right":          # 如果摄像头朝“右侧”安装            wx = (self.c_x - x) * self.ratio             # 对应坐标系旋转 90 °            wy = (y - self.c_y) * self.ratio        return wx, wy                                    # 返回实际偏移量（单位 mm）    # ---------------- 图像缩放（模型输入尺寸） ----------------    def transform_frame(self, frame):                    # 将原图缩放为 224 × 224（示例值，以配置为准）        frame, ratio, (dw, dh) = self.yolo.letterbox(frame, (grabParams.IMG_SIZE, grabParams.IMG_SIZE))        return frame                                     # 返回缩放后图像    def transform_frame_128(self, frame):                # 再缩放一份 128 × 128 给 ONNX 模型用        frame, ratio, (dw, dh) = self.yolo.letterbox(frame, (128, 128))        return frame        # ---------------- 物体检测 ----------------    def obj_detect(self, img):                           # 输入：原始摄像头图像；输出：目标像素坐标 + 类别        x = y = 0                                        # 初始化目标中心像素坐标        img_ori = img                                    # 保留原图备份，用于画框显示        img_ori = self.transform_frame(img_ori)          # 备份图缩放到 224 × 224        img = self.transform_frame_128(img)              # 再缩一份 128 × 128 给模型        net = cv2.dnn.readNetFromONNX("/home/robuster/beetle_ai/scripts/beetle_obj.onnx")  # 加载 ONNX 权重        t1 = time.time()                                 # 计时开始        blob = cv2.dnn.blobFromImage(img, 1 / 255.0, (128, 128), [0, 0, 0], swapRB=True, crop=False)  # 构造输入 blob        net.setInput(blob)                               # 把 blob 喂给网络        outputs = net.forward(net.getUnconnectedOutLayersNames())[0]  # 前向推理，取输出张量        boxes, classes, scores = self.yolo.yolov5_post_process_simple(outputs)  # 后处理得框/类别/分数        t2 = time.time()                                 # 计时结束        if boxes is not None:                            # 如果检测到物体            boxes = boxes * 5                            # 把 128 尺度映射回 224 尺度（粗暴乘以 5）            detected_class = classes[0]                  # 取最高置信度类别            self.yolo.draw_single(img_ori, boxes[0], scores[0], classes[0])  # 在备份图上画框            left, top, right, bottom = boxes[0]          # 解包框坐标            x = int((left + right) / 2)                  # 计算中心 x            y = int((top + bottom) / 2)                  # 计算中心 y        cv2.imshow("figure", img_ori)                    # 显示画框结果        cv2.waitKey(10)                                  # 等待 10 ms，让窗口刷新        #print("time: " + str(t2 - t1) + "s")             # 打印纯推理耗时        if x + y > 0:                                    # 如果拿到了有效坐标            return x, y, detected_class                  # 返回中心像素 + 类别        else:            return None                                    # 否则返回空    # ---------------- 主入口 ----------------    def run(self):                                       # 主入口，只做初始化        self.mc.set_color(0, 0, 255)                     # LED 变蓝，表示“忙碌”        self.init_mycobot()                              # 回到待命姿态    # ---------------- 调试用图像显示 ----------------    def show_image(self, img):                           # 封装一个可选的调试图像显示        if grabParams.debug and args.debug:              # 配置与命令行同时开启才显示            cv2.imshow("figure", img)                    # 弹出窗口            cv2.waitKey(50)                              # 等待 50 ms    # ---------------- 夹爪控制 ----------------    def grap(self, flag):                                # True=闭合抓取，False=张开        if flag:            self.mc.set_gripper_value(45, 60)             # 设置夹爪闭合到 40（0 最松，100 最紧）            time.sleep(0.1)                                # 等待 1 s 动作完成        else:            self.mc.set_gripper_state(0, 60)              # 设置夹爪完全张开            #time.sleep(0.3)    # ---------------- 坐标移动封装 ----------------    def move_to_target_coords(self, coords, speed):      # 封装坐标移动，方便以后复用        print("move_to_target_coords")                   # 打印提示        self.mc.send_coords(coords, speed, 1)            # 以 speed 速度移动到 coords，模式 1        time.sleep(1)                                    # 等待 2 s 稳定    # ------------------------------------------------------------------    # 以下 4 个函数是“分类放置”专用，角度值通过手调得到，分别对应：    # 左 1、左 2、右 1、右 2 四个不同落点    # ------------------------------------------------------------------    def run_put_down(self, side, seq):        """        side: "left" | "right"   放到哪一侧        seq:  1 | 2               同一侧的序号（落点 1 还是落点 2）        """        #根据 (side, seq) 选取“放置前过渡角度”        if side == "left" and seq == 0:            angles_ready = [49.04, -66.26, -20.91, 20.39, -5.53, 56.77]#zuo 1        elif side == "left" and seq == 1:            angles_ready = [-25.77, -52.21, -25.93, -11.51, -5.27, 57.65]#you 1        elif side == "right" and seq == 0:            angles_ready = [55.35, -25.87, -88.85, 40.17, -6.24, 48.16]#zuo 2        elif side == "right" and seq == 1:  # right 2            angles_ready = [-16.08, -37.0, -59.85, 8.17, -4.57, 28.03]#you 2        if  seq==1 :            angles_up = [49.13,-31.02,-25.92,-4.83,-7.03,52.82]        else:            angles_up = [-23.2, -51.5, -23.64, -16.78, -5.0, 34.1]        angles_home = [0.43, 1.93, -58.79, -28.74, -3.95, 45.26]        self.grap(True)                       # 夹爪闭合（确保抓住）        self.mc.send_angles(angles_ready, LGJ_speed) # 移动到放置过渡姿态        time.sleep(1.4)        self.grap(False)                      # 张开夹爪，放下物体        print("open")        angle_T=self.mc.get_angles()        angle_T[1]= angle_T[1]+30        self.mc.send_angles(angle_T, LGJ_speed)                 # self.mc.send_angles(angles_up, 60)    # 抬手避让        time.sleep(0.6)        self.mc.send_angles(angles_home, 50)  # 回到安全角度        time.sleep(2.5)        # ===================================================================#                           主流程# ===================================================================i = 0                                                    # 计数器：已抓取/放置次数left = 0                                                 # 左放置序号（1=第一次放左）right = 0                                               # 右放置序号（1=第一次放右）detect = Detect_marker()                                 # 新建检测抓取器对象detect.run()                                             # 初始化机械臂while i < 4:                                             # 总共抓取 4 次    cap = cv2.VideoCapture(2)                            # 打开摄像头（设备号 2，根据实际修改）    init_num = 0                                         # 以下变量本例未再用，保留兼容    nparams = 0    num = 0    miss = 0    while True:                                          # 不断读帧直到成功检测到物体        retval, frame = cap.read()                       # 读一帧        if not retval:                                   # 如果没读到，继续            continue        frame = cv2.flip(frame, 0)                       # 垂直翻转（摄像头倒装）        frame = cv2.flip(frame, 1)                       # 水平翻转（镜像）        detect_result = detect.obj_detect(frame)         # YOLO 检测        if detect_result is None:                        # 没检测到，继续读帧            continue        else:                                            # 检测到目标            x, y, class_detected = detect_result         # 解包：中心像素 + 类别            real_x, real_y = detect.get_position(x, y)   # 换算成 mm 偏移            coords_now = basic.get_coords()              # 获取机械臂当前坐标（6 维）            if len(coords_now) == 6:                     # 如果读回有效坐标                coords = coords_now                      # 更新全局 coords（后续移动基准）            detect.move(real_x + grabParams.x_bias - 2, real_y + grabParams.y_bias)  # 抓取            print("class_detected:", class_detected)     # 打印类别            break                                        # 跳出检测循环    cap.release()                                        # 释放摄像头    cv2.destroyAllWindows()                              # 关闭 OpenCV 窗口    # 以下逻辑：第一次检测到的类别记为 add1，交替放左/右，且左/右各两个落点    if class_detected == 4:        add = 'bird'    else :        add = 'cat'       if detect_result is not None:        if add == 'cat':            detect.run_put_down("left", left)            print("run_put_down_left",left)            left = left+1            if left >= 2 :                left=left%2        elif add == 'bird':                detect.run_put_down("right", right)            print("run_put_down_right",right)            right = right+1            if right >=2 :                right=right%2    i += 1                                               # 完成一次抓取+放置，计数器 +1    print("Finish:",i,add)